<script setup lang="ts">
import { ref } from 'vue'

// Props
interface Props {
  selectedDistrictId?: number | null
}

const props = defineProps<Props>()

// Emits
const emit = defineEmits<{
  'district-click': [districtName: string, fillColor: string]
  'district-hover': [districtName: string | null]
}>()

const active = defineModel()
const activeName = defineModel('name')

watch(
	() => active.value,
	(val) => {
		if (!val) {
			const paths = (document.querySelector('.region3') as SVGSVGElement)?.querySelectorAll(
				'path'
			)
			paths.forEach((path) => {
				const originalColor = path.getAttribute('data-fill-color')
				path.style.fill = originalColor || ''
			})
		}
	},
	{deep:true}
)
// State
const hoveredDistrict = ref<string | null>(null)
const selectedDistrict = ref<string | null>(null)

// Event handlers
function handleDistrictClick (event: MouseEvent) {
  const target = event.target as SVGPathElement
  const districtName = target.getAttribute('data-district-name')
  const fillColor = target.getAttribute('data-fill-color')
  const districtId = target.getAttribute('id')
  const paths = (document.querySelector('.region3') as SVGSVGElement)?.querySelectorAll(
        'path'
    )
  if (districtName && fillColor && districtId) {
    selectedDistrict.value = districtName
	active.value = districtId
	activeName.value = districtName
    emit('district-click', districtName, fillColor)
    console.log('District clicked:', districtName)
    target.style.fill = '#004494'
	  paths.forEach((path) => {
      const originalColor = path.getAttribute('data-fill-color')
      if (path.id === districtId) {
        path.style.fill = '#004494'
      } else if (originalColor) {
        path.style.fill = originalColor
      }
    })
  }
}

function handleMouseEnter(event: MouseEvent) {
  const target = event.target as SVGPathElement
  const districtName = target.getAttribute('data-district-name')
  const fillColor = target.getAttribute('data-fill-color') || ''
  const districtId = target.getAttribute("id");
  if (districtName) {
    hoveredDistrict.value = districtName
    emit('district-hover', districtName)
    
    // Change fill color on hover
    if (fillColor) {
        if (active.value) {
            target.style.fill = active.value === districtId ? "#004494":target.style.fill = adjustColorBrightness(fillColor, -20)
        }
        else target.style.fill = adjustColorBrightness(fillColor, -20)
        target.style.cursor = 'pointer'
    }
  }
}

function handleMouseLeave(event: MouseEvent) {
    const target = event.target as SVGPathElement
    const fillColor = target.getAttribute('data-fill-color') || ''
    const districtId = target.getAttribute("id");
    hoveredDistrict.value = null
    emit('district-hover', null)

    // Restore original fill color
    if (fillColor) {
        if (active.value) {
            target.style.fill = active.value === districtId ? "#004494":fillColor
        }
        else target.style.fill = fillColor
    }
}

// Helper function to adjust color brightness
function adjustColorBrightness(color: string, percent: number): string {
  const num = parseInt(color.replace('#', ''), 16)
  const amt = Math.round(2.55 * percent)
  const R = (num >> 16) + amt
  const G = ((num >> 8) & 0x00ff) + amt
  const B = (num & 0x0000ff) + amt

  return (
    '#' +
    (
      0x1000000 +
      (R < 255 ? (R < 1 ? 0 : R) : 255) * 0x10000 +
      (G < 255 ? (G < 1 ? 0 : G) : 255) * 0x100 +
      (B < 255 ? (B < 1 ? 0 : B) : 255)
    )
      .toString(16)
      .slice(1)
      .toUpperCase()
  )
}
</script>

<style scoped>
/* Hover effect */
svg path[data-district-name] {
  transition: fill 0.2s ease;
  cursor: pointer;
}

svg path[data-district-name]:hover {
  opacity: 0.8;
}
</style>
